export type SizeBin = 'S' | 'M' | 'L' | 'XL';

export const SIZE_BIN_LABEL: Record<SizeBin, string> = {
  S: 'S (1-3)',
  M: 'M (4-7)',
  L: 'L (8-15)',
  XL: 'XL (16+)',
};

/**
 * 規模 total を S/M/L/XL のビンに分類する。
 * S:  1-3   (軽い)
 * M:  4-7   (中)
 * L:  8-15  (重い)
 * XL: 16+   (巨大)
 * total <= 0 の場合も S とする（仕様簡略化）。
 */
export function getSizeBin(total: number): SizeBin {
  if (total <= 3) return 'S';
  if (total <= 7) return 'M';
  if (total <= 15) return 'L';
  return 'XL';
}
```

