      <tr className="bg-muted/40">
        <td colSpan={columns.length} className="px-3 py-1.5 text-xs font-semibold text-muted-foreground">
          {projectName} <span className="tabular-nums">({groupRows.length})</span>
        </td>
      </tr>
      {groupRows.map(renderRow)}
    </Fragment>
  ))
} else {
  body = rows.map(renderRow)
}

return (
  // ...
  <tbody>
    {body}
    {data.length === 0 && (
      <tr><td colSpan={columns.length} className="px-3 py-6 text-center text-muted-foreground">
        {sizeBinFilter ? `規模 ${sizeBinFilter} に該当する PLAN はありません` : 'PLAN がありません'}
      </td></tr>
    )}
  </tbody>
)
```

4. `npm run build` で確認。

## 実装手順

1. import を追加。

```tsx
import { ViewSwitcher, type ViewType } from '@/components/view-switcher'
import { GroupingToggle } from '@/components/grouping-toggle'
import { PlanTable } from '@/components/plan-table'
import { SizeHistogram } from '@/components/size-histogram'
import type { SizeBin } from '@/lib/plan-size'
```

2. `Home` コンポーネント内に state を追加。

```tsx
const [activeView, setActiveView] = useState<ViewType>('kanban')
const [kanbanGrouping, setKanbanGrouping] = useState(false)
const [tableGrouping, setTableGrouping] = useState(false)
const [sizeBinFilter, setSizeBinFilter] = useState<SizeBin | null>(null)
```

3. ヘッダー直下のレイアウトを以下に変更（既存のタイトル + バッジ群はそのまま）。

```tsx
<div className="flex flex-wrap items-center justify-between gap-3">
  <ViewSwitcher activeView={activeView} onViewChange={setActiveView} />
  <GroupingToggle
    enabled={activeView === 'kanban' ? kanbanGrouping : tableGrouping}
    onToggle={(next) => {
      if (activeView === 'kanban') setKanbanGrouping(next)
      else setTableGrouping(next)
    }}
  />
</div>
```

4. 既存の `<KanbanBoard plans={filteredPlans} />` を以下に置き換え。

```tsx
{activeView === 'kanban' ? (
  <KanbanBoard plans={filteredPlans} groupByProject={kanbanGrouping} />
) : (
  <div className="space-y-4">
    <SizeHistogram
      plans={filteredPlans}
      activeBin={sizeBinFilter}
      onBinClick={(bin) => setSizeBinFilter((prev) => (prev === bin ? null : bin))}
    />
    <PlanTable
      plans={filteredPlans}
      sizeBinFilter={sizeBinFilter}
      groupByProject={tableGrouping}
    />
  </div>
)}
```

5. ビュー切替時に sizeBinFilter をリセットしたい場合は、`setActiveView` をラップする関数を用意する（仕様: ビュー独立だが SizeBinFilter は Table 専用なので Kanban 切替時のリセットは不要 → そのまま）。

6. `npm run build` と `npm run dev` で動作確認。
